import{_ as t,c as i,o as n,a1 as a}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"Sicherheit: Datenschutz | opencode-mystatus","description":"Erfahren Sie über den Sicherheitsmechanismus des opencode-mystatus-Plugins: schreibgeschützter lokaler Dateizugriff, automatische API-Key-Maskierung, nur Aufruf offizieller Schnittstellen, keine Datenübertragung, -speicherung und Datenschutz.","frontmatter":{"title":"Sicherheit: Datenschutz | opencode-mystatus","sidebarTitle":"Sicherheit","subtitle":"Sicherheit: Datenschutz","description":"Erfahren Sie über den Sicherheitsmechanismus des opencode-mystatus-Plugins: schreibgeschützter lokaler Dateizugriff, automatische API-Key-Maskierung, nur Aufruf offizieller Schnittstellen, keine Datenübertragung, -speicherung und Datenschutz.","tags":["Sicherheit","Privatsphäre","FAQ"],"prerequisite":[],"order":2},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/faq/security/index.md","filePath":"de/vbgate/opencode-mystatus/faq/security/index.md"}'),r={name:"de/vbgate/opencode-mystatus/faq/security/index.md"};function s(l,e,d,o,u,h){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="sicherheit-und-privatsphare-lokaler-dateizugriff-api-maskierung-offizielle-schnittstellen" tabindex="-1">Sicherheit und Privatsphäre: Lokaler Dateizugriff, API-Maskierung, offizielle Schnittstellen <a class="header-anchor" href="#sicherheit-und-privatsphare-lokaler-dateizugriff-api-maskierung-offizielle-schnittstellen" aria-label="Permalink to &quot;Sicherheit und Privatsphäre: Lokaler Dateizugriff, API-Maskierung, offizielle Schnittstellen&quot;">​</a></h1><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Bei der Verwendung von Drittanbieter-Tools sind Sie am meisten besorgt über:</p><ul><li>&quot;Liest es meinen API-Key?&quot;</li><li>&quot;Werden meine Authentifizierungsinformationen an einen Server hochgeladen?&quot;</li><li>&quot;Gibt es ein Risiko für Datenlecks?&quot;</li><li>&quot;Was passiert, wenn es meine Konfigurationsdateien ändert?&quot;</li></ul><p>Diese Bedenken sind verständlich, besonders bei der Verarbeitung von sensiblen KI-Plattform-Authentifizierungsinformationen. Dieses Tutorial erklärt ausführlich, wie opencode-mystatus Ihre Daten und Privatsphäre durch das Design schützt.</p><div class="info custom-block"><p class="custom-block-title">Lokalitätsprinzip</p><p>opencode-mystatus befolgt das Prinzip &quot;Schreibgeschützer lokaler Dateizugriff + direkte Abfrage offizieller APIs&quot;. Alle sensiblen Operationen werden auf Ihrem Computer abgeschlossen, ohne dass ein Drittanbieterserver durchlaufen wird.</p></div><h2 id="grundlegende-idee" tabindex="-1">Grundlegende Idee <a class="header-anchor" href="#grundlegende-idee" aria-label="Permalink to &quot;Grundlegende Idee&quot;">​</a></h2><p>Das Sicherheitsdesign des Plugins umfasst drei Kernprinzipien:</p><ol><li><strong>Schreibgeschützkeitsprinzip</strong>: Nur Lesen lokaler Authentifizierungsdateien, kein Schreiben oder Ändern von Inhalten</li><li><strong>Offizielle Schnittstellen</strong>: Nur Aufruf der offiziellen APIs der einzelnen Plattformen, ohne Verwendung von Drittanbieterdiensten</li><li><strong>Datenmaskierung</strong>: Automatisches Ausblenden sensibler Informationen (z. B. API-Key) bei der Anzeige</li></ol><p>Diese drei Prinzipien werden übereinander gestapelt, um sicherzustellen, dass Ihre Daten während des gesamten Prozesses vom Lesen bis zur Anzeige sicher sind.</p><h2 id="lokaler-dateizugriff-schreibgeschutzt" tabindex="-1">Lokaler Dateizugriff (schreibgeschützt) <a class="header-anchor" href="#lokaler-dateizugriff-schreibgeschutzt" aria-label="Permalink to &quot;Lokaler Dateizugriff (schreibgeschützt)&quot;">​</a></h2><h3 id="welche-dateien-liest-das-plugin" tabindex="-1">Welche Dateien liest das Plugin <a class="header-anchor" href="#welche-dateien-liest-das-plugin" aria-label="Permalink to &quot;Welche Dateien liest das Plugin&quot;">​</a></h3><p>Das Plugin liest nur zwei lokale Konfigurationsdateien, und zwar <strong>nur schreibgeschützt</strong>:</p><table tabindex="0"><thead><tr><th>Dateipfad</th><th>Zweck</th><th>Quellcodeposition</th></tr></thead><tbody><tr><td><code>~/.local/share/opencode/auth.json</code></td><td>Offizieller Authentifizierungsspeicher von OpenCode</td><td><code>mystatus.ts:35</code></td></tr><tr><td><code>~/.config/opencode/antigravity-accounts.json</code></td><td>Antigravity-Plugin-Kontospeicher</td><td><code>google.ts</code> (Leselogik)</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Keine Dateiänderung</p><p>Im Quellcode wird nur die Funktion <code>readFile</code> zum Lesen von Dateien verwendet, ohne <code>writeFile</code> oder andere Änderungsoperationen. Das bedeutet, dass das Plugin versehentlich Ihre Konfiguration nicht überschreibt.</p></div><h2 id="offizielle-schnittstellenaufrufe" tabindex="-1">Offizielle Schnittstellenaufrufe <a class="header-anchor" href="#offizielle-schnittstellenaufrufe" aria-label="Permalink to &quot;Offizielle Schnittstellenaufrufe&quot;">​</a></h2><h3 id="welche-apis-ruft-das-plugin-auf" tabindex="-1">Welche APIs ruft das Plugin auf <a class="header-anchor" href="#welche-apis-ruft-das-plugin-auf" aria-label="Permalink to &quot;Welche APIs ruft das Plugin auf&quot;">​</a></h3><p>Das Plugin ruft nur die <strong>offiziellen APIs</strong> der einzelnen Plattformen auf, ohne Drittanbieterserver:</p><table tabindex="0"><thead><tr><th>Plattform</th><th>API-Endpunkt</th><th>Zweck</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>https://chatgpt.com/backend-api/wham/usage</code></td><td>Kreditabfrage</td></tr><tr><td>Zhipu AI</td><td><code>https://bigmodel.cn/api/monitor/usage/quota/limit</code></td><td>Token-Kreditabfrage</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Sicherheit offizieller APIs</p><p>Diese API-Endpunkte sind die offiziellen Schnittstellen der jeweiligen Plattformen und verwenden HTTPS-verschlüsselte Übertragung. Das Plugin dient lediglich als &quot;Client&quot; zum Senden von Anfragen, speichert oder leitet keine Daten weiter.</p></div><h2 id="privatspharezusammenfassung" tabindex="-1">Privatsphärezusammenfassung <a class="header-anchor" href="#privatspharezusammenfassung" aria-label="Permalink to &quot;Privatsphärezusammenfassung&quot;">​</a></h2><h3 id="was-das-plugin-nicht-tut" tabindex="-1">Was das Plugin nicht tut <a class="header-anchor" href="#was-das-plugin-nicht-tut" aria-label="Permalink to &quot;Was das Plugin nicht tut&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Pluginkonfiguration</th></tr></thead><tbody><tr><td>Daten speichern</td><td>❌ Speichert keine Benutzerdaten</td></tr><tr><td>Daten hochladen</td><td>❌ Lädt keine Daten an Drittanbieterserver hoch</td></tr><tr><td>Ergebnisse zwischenspeichern</td><td>❌ Speichert keine Abfrageergebnisse</td></tr><tr><td>Dateien ändern</td><td>❌ Ändert keine lokalen Konfigurationsdateien</td></tr><tr><td>Protokolle aufzeichnen</td><td>❌ Zeichnet keine Nutzungsprotokolle auf</td></tr></tbody></table><h3 id="was-das-plugin-tut" tabindex="-1">Was das Plugin tut <a class="header-anchor" href="#was-das-plugin-tut" aria-label="Permalink to &quot;Was das Plugin tut&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Pluginkonfiguration</th></tr></thead><tbody><tr><td>Dateien lesen</td><td>✅ Nur schreibgeschütztes Lesen lokaler Authentifizierungsdateien</td></tr><tr><td>APIs aufrufen</td><td>✅ Nur Aufruf offizieller API-Endpunkte</td></tr><tr><td>Maskierte Anzeige</td><td>✅ Automatisches Ausblenden von API-Keys und anderen sensiblen Informationen</td></tr><tr><td>---</td><td>---</td></tr></tbody></table><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li><strong>Schreibgeschütztkeitsprinzip</strong>: Das Plugin liest nur lokale Authentifizierungsdateien, ändert keine Inhalte</li><li><strong>API-Maskierung</strong>: Beim Anzeigen werden kritische Teile des API-Keys ausgeblendet</li><li><strong>Offizielle Schnittstellen</strong>: Nur Aufruf der offiziellen APIs der einzelnen Plattformen, ohne Drittanbieterdienste</li><li><strong>Open-Source-Transparenz</strong>: Alle Codes sind open-source, Sicherheitsmechanismen können selbst auditierbar sein</li></ul><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Authentifizierungsdateilesung</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts#L38-L40" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>38-40</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>maskString(str, showChars = 4)</code>: Maskierte Anzeige sensibler Zeichenketten, zeigt erste und letzte <code>showChars</code> Zeichen an, ersetzt den Mittelteil mit <code>****</code></li></ul></details>',30)])])}const g=t(r,[["render",s]]);export{f as __pageData,g as default};
